// // This module generates a 2-bit output based on an 8-bit error input and an 8-bit error level input. When the error value is greater than the error level, the output 'noise' takes the upper two bits of the error; otherwise, it outputs a fixed value of 11.
module top_module(error, noise,err_level);output [1:0] noise; 
  input [7:0] error; 
  input [7:0] err_level; 
  reg [1:0] noise; 
  always@(error) 
  begin 
  if (error < err_level) 
  noise = error[1:0]; 
  else 
  noise = 2'b00; 
  end 
 endmodule
